// Login.js  (FINAL FIXED)
import React, { useState } from "react";
import { loginUser } from "./api/auth";
import "./Login.css";

export default function Login() {
  const [empId, setEmpId] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);

    try {
      const res = await loginUser(empId, password);

      if (res.data?.success) {
        // STORE USER
        localStorage.setItem("empId", res.data.employee.empId);
        localStorage.setItem("empName", res.data.employee.empName);

        // REDIRECT TO DASHBOARD
        window.location.href = "/dashboard";
      } 
      else if (res.data?.message === "INVALID_LOGIN") {
        alert("Invalid Employee ID or Password");
      } 
      else {
        alert("Server Error");
      }
    } catch (err) {
      alert("Server Error");
    }

    setBusy(false);
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            marginBottom: 18,
          }}
        >
          <img
            src="/logo.png"
            alt="PRASA Logo"
            style={{
              height: 60,
              width: 60,
              objectFit: "contain",
              background: "#fff",
              borderRadius: 12,
              marginBottom: 8,
            }}
          />
          <h2 className="title">Employee Login</h2>
        </div>

        <form onSubmit={submit}>
          <input
            className="input-box"
            placeholder="EMP ID"
            value={empId}
            onChange={(e) => setEmpId(e.target.value)}
          />

          <input
            className="input-box"
            placeholder="Password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button className="btn-login" type="submit" disabled={busy}>
            {busy ? "Logging In..." : "Login"}
          </button>
        </form>
      </div>
    </div>
  );
}
